import{_ as t,o,c as a,ad as r}from"./chunks/framework.DdcUsuRQ.js";const m=JSON.parse('{"title":"OKLCH","description":"The perceptually uniform polar form of Oklab that every iridis ColorRecord carries. Coordinates, why the pipeline reasons in this space, and the sRGB conversion chain.","frontmatter":{"title":"OKLCH","description":"The perceptually uniform polar form of Oklab that every iridis ColorRecord carries. Coordinates, why the pipeline reasons in this space, and the sRGB conversion chain.","head":[["link",{"rel":"canonical","href":"https://studnicky.github.io/iridis/reference/oklch"}],["meta",{"property":"og:url","content":"https://studnicky.github.io/iridis/reference/oklch"}],["meta",{"property":"og:title","content":"OKLCH: iridis"}],["meta",{"property":"og:description","content":"The perceptually uniform polar form of Oklab that every iridis ColorRecord carries. Coordinates, why the pipeline reasons in this space, and the sRGB conversion chain."}],["meta",{"name":"twitter:title","content":"OKLCH: iridis"}],["meta",{"name":"twitter:description","content":"The perceptually uniform polar form of Oklab that every iridis ColorRecord carries. Coordinates, why the pipeline reasons in this space, and the sRGB conversion chain."}],["meta",{"name":"description","content":"The perceptually uniform polar form of Oklab that every iridis ColorRecord carries. Coordinates, why the pipeline reasons in this space, and the sRGB conversion chain."}],["meta",{"property":"article:modified_time","content":"2026-05-17T16:04:29.000Z"}],["meta",{"property":"article:author","content":"Andrew Studnicky"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"iridis\\",\\"item\\":\\"https://studnicky.github.io/iridis/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Reference\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"OKLCH\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference/oklch\\"}]}"]]},"headers":[],"relativePath":"reference/oklch.md","filePath":"reference/oklch.md","lastUpdated":1779033869000}'),i={name:"reference/oklch.md"};function s(d,e,c,n,l,h){return o(),a("div",null,[...e[0]||(e[0]=[r(`<h1 id="oklch" tabindex="-1">OKLCH <a class="header-anchor" href="#oklch" aria-label="Permalink to &quot;OKLCH&quot;">​</a></h1><p>OKLCH is the canonical color space inside <span class="iridis-brand">iridis</span>. Every <code>ColorRecord</code> carries OKLCH coordinates regardless of the input format. The pipeline reasons about lightness, chroma, and hue in this space.</p><h2 id="coordinates" tabindex="-1">Coordinates <a class="header-anchor" href="#coordinates" aria-label="Permalink to &quot;Coordinates&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Channel</th><th>Range</th><th>Meaning</th></tr></thead><tbody><tr><td>L (lightness)</td><td><code>[0, 1]</code></td><td>perceptual lightness, 0 = black, 1 = white</td></tr><tr><td>C (chroma)</td><td><code>[0, ~0.5]</code></td><td>distance from the neutral grey axis</td></tr><tr><td>h (hue)</td><td><code>[0, 360)</code> degrees</td><td>angle on the chromaticity plane</td></tr></tbody></table><p>OKLCH is the polar form of Oklab, Björn Ottosson&#39;s perceptually uniform color space (2020). The Cartesian form has axes (L, a, b); the polar form keeps L and replaces (a, b) with chroma C = √(a² + b²) and hue h = atan2(b, a). Polar coordinates are easier to manipulate semantically, &quot;shift hue&quot; and &quot;raise chroma&quot; are coordinate operations rather than vector projections.</p><h2 id="why-oklch" tabindex="-1">Why OKLCH <a class="header-anchor" href="#why-oklch" aria-label="Permalink to &quot;Why OKLCH&quot;">​</a></h2><p>Three properties matter for a palette engine:</p><ol><li><strong>Perceptual uniformity.</strong> Equal numeric steps in L produce roughly equal perceived steps in lightness. This is what HSL and HSV fail at, and it is what allows <code>lighten</code> and <code>darken</code> to behave predictably across hues.</li><li><strong>Independent hue and lightness.</strong> Rotating h holds lightness constant. In HSL, sliding hue while holding lightness can produce visibly different brightness because HSL&#39;s L is the average of max and min RGB channels rather than perceived luminance.</li><li><strong>CSS support.</strong> <code>oklch(l c h)</code> is a Level 4 CSS Color value. Modern browsers consume it natively, which means the same coordinates the engine reasons about can be written directly to a stylesheet without round-tripping through sRGB.</li></ol><p>These properties make every other primitive simpler. Contrast enforcement, family expansion, mix, lerp, and the v2 vector-space framing all assume perceptual uniformity and independent axes.</p><h2 id="conversion" tabindex="-1">Conversion <a class="header-anchor" href="#conversion" aria-label="Permalink to &quot;Conversion&quot;">​</a></h2><p>OKLCH ↔ RGB is implemented inline in <code>ColorRecordFactory</code> (<code>packages/core/src/math/ColorRecordFactory.ts</code>). The forward direction is:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes iridis iridis vp-code" tabindex="0"><code><span class="line"><span>sRGB (gamma)  →  linear sRGB  →  LMS cone responses (matrix M₁)</span></span>
<span class="line"><span>              →  cube-root non-linearity</span></span>
<span class="line"><span>              →  Oklab (matrix M₂)</span></span>
<span class="line"><span>              →  OKLCH (polar form)</span></span></code></pre></div><p>The matrices and the cube-root step are Ottosson&#39;s published constants. The reverse path inverts every step in order: polar → Oklab → cube → linear sRGB → gamma encode.</p><p>Hue is computed with <code>atan2(b, a)</code> and normalised to <code>[0, 360)</code>. Chroma is clamped to <code>[0, 0.5]</code>; values above that are out of the sRGB gamut and the gamma-encoded output is clamped to <code>[0, 1]</code> per channel.</p><h2 id="math-primitives" tabindex="-1">Math primitives <a class="header-anchor" href="#math-primitives" aria-label="Permalink to &quot;Math primitives&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Primitive</th><th>File</th><th>Behaviour</th></tr></thead><tbody><tr><td><code>oklchToRgb</code></td><td><code>packages/core/src/math/OklchToRgb.ts</code></td><td>builds a <code>ColorRecord</code> from L, C, h via <code>ColorRecordFactory.fromOklch</code></td></tr><tr><td><code>rgbToOklch</code></td><td><code>packages/core/src/math/RgbToOklch.ts</code></td><td>builds a <code>ColorRecord</code> from R, G, B via <code>ColorRecordFactory.fromRgb</code></td></tr><tr><td><code>mixOklch</code></td><td><code>packages/core/src/math/MixOklch.ts</code></td><td>linear interpolation in OKLCH (perceptual)</td></tr><tr><td><code>lighten</code></td><td><code>packages/core/src/math/Lighten.ts</code></td><td>adjusts L upward</td></tr><tr><td><code>darken</code></td><td><code>packages/core/src/math/Darken.ts</code></td><td>adjusts L downward</td></tr><tr><td><code>saturate</code></td><td><code>packages/core/src/math/Saturate.ts</code></td><td>adjusts C upward</td></tr><tr><td><code>desaturate</code></td><td><code>packages/core/src/math/Desaturate.ts</code></td><td>adjusts C downward</td></tr><tr><td><code>hueShift</code></td><td><code>packages/core/src/math/HueShift.ts</code></td><td>rotates h</td></tr><tr><td><code>deltaE2000</code></td><td><code>packages/core/src/math/DeltaE2000.ts</code></td><td>perceptual distance between two <code>ColorRecord</code> values</td></tr><tr><td><code>clampOklch</code></td><td><code>packages/core/src/tasks/clamp/ClampOklch.ts</code></td><td>task that clamps OKLCH coordinates to a configured range</td></tr></tbody></table><h2 id="where-it-appears" tabindex="-1">Where it appears <a class="header-anchor" href="#where-it-appears" aria-label="Permalink to &quot;Where it appears&quot;">​</a></h2><ul><li>Every <code>ColorRecord</code> has an <code>oklch: { l, c, h }</code> field. This is the field the engine reads when it needs to reason about the color.</li><li><code>intake:oklch</code> (<code>packages/core/src/tasks/intake/IntakeOklch.ts</code>) accepts <code>{l, c, h}</code> objects directly.</li><li><code>resolve:roles</code> matches colors to semantic roles using OKLCH distance.</li><li><code>expand:family</code> derives related roles from a source role by offsetting L and C ranges in OKLCH.</li><li><code>enforce:contrast</code> walks contrast pairs and nudges foreground roles by adjusting L in OKLCH until the WCAG or APCA threshold is met.</li><li><code>emit:cssVars</code> can emit values as <code>oklch(l c h)</code> for direct CSS consumption.</li></ul>`,18)])])}const u=t(i,[["render",s]]);export{m as __pageData,u as default};
